import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import toast from 'react-hot-toast';
import useAuthStore from '../store/authStore';
import './Auth.css';

const isValidName = value => {
  const normalized = value.trim().replace(/\s+/g, ' ');
  return normalized.length >= 2 && normalized.length <= 100 && !/\d/.test(normalized);
};

const isValidPhone = value => /^\d{10,11}$/.test(value);

export default function DangKy() {
  const [form, setForm] = useState({
    hoTen: '',
    email: '',
    soDienThoai: '',
    matKhau: '',
    xacNhanMatKhau: '',
  });
  const { dangKy, loading, error, clearError } = useAuthStore();
  const navigate = useNavigate();

  const handleSubmit = async e => {
    e.preventDefault();

    if (!isValidName(form.hoTen)) {
      toast.error('Ho va ten phai tu 2-100 ky tu va khong duoc chua so');
      return;
    }

    if (!isValidPhone(form.soDienThoai)) {
      toast.error('So dien thoai phai gom 10 hoac 11 chu so');
      return;
    }

    if (form.matKhau !== form.xacNhanMatKhau) {
      toast.error('Mat khau xac nhan khong khop');
      return;
    }

    const ok = await dangKy({
      hoTen: form.hoTen,
      email: form.email,
      soDienThoai: form.soDienThoai,
      matKhau: form.matKhau,
    });

    if (ok) {
      toast.success('Dang ky thanh cong!');
      navigate('/xac-thuc');
      return;
    }

    toast.error(useAuthStore.getState().error || 'Dang ky that bai');
  };

  const set = (key, value) => {
    clearError();
    setForm(current => ({ ...current, [key]: value }));
  };

  return (
    <div className="auth-wrapper">
      <div className="auth-card card">
        <div className="card-body">
          <div className="auth-logo">RoomMate</div>
          <div className="auth-kicker">Navy Edition</div>
          <h2 className="auth-title">Tao tai khoan moi</h2>
          <p className="auth-subtitle">Bat dau hanh trinh tim ban o ghep an toan va minh bach.</p>
          {error && <div className="alert alert-danger">{error}</div>}
          <form onSubmit={handleSubmit}>
            <div className="form-group">
              <label className="form-label">Ho va ten</label>
                <input
                  className="form-control"
                  required
                  maxLength={100}
                  autoComplete="name"
                  value={form.hoTen}
                  onChange={e => set('hoTen', e.target.value)}
                placeholder="Nguyen Van A"
              />
            </div>
            <div className="grid-2">
              <div className="form-group">
                <label className="form-label">Email</label>
                <input
                  className="form-control"
                  type="email"
                  required
                  autoComplete="email"
                  value={form.email}
                  onChange={e => set('email', e.target.value)}
                  placeholder="example@email.com"
                />
              </div>
              <div className="form-group">
                <label className="form-label">So dien thoai</label>
                <input
                  className="form-control"
                  required
                  inputMode="numeric"
                  pattern="[0-9]{10,11}"
                  maxLength={11}
                  autoComplete="tel"
                  value={form.soDienThoai}
                  onChange={e => set('soDienThoai', e.target.value.replace(/\D/g, ''))}
                  placeholder="0901234567"
                />
              </div>
            </div>
            <div className="grid-2">
              <div className="form-group">
                <label className="form-label">Mat khau</label>
                <input
                  className="form-control"
                  type="password"
                  required
                  minLength={6}
                  autoComplete="new-password"
                  value={form.matKhau}
                  onChange={e => set('matKhau', e.target.value)}
                  placeholder="Toi thieu 6 ky tu"
                />
              </div>
              <div className="form-group">
                <label className="form-label">Xac nhan mat khau</label>
                <input
                  className="form-control"
                  type="password"
                  required
                  minLength={6}
                  autoComplete="new-password"
                  value={form.xacNhanMatKhau}
                  onChange={e => set('xacNhanMatKhau', e.target.value)}
                  placeholder="Nhap lai mat khau"
                />
              </div>
            </div>
            <button className="btn btn-primary btn-block auth-submit" disabled={loading}>
              {loading ? 'Dang tao tai khoan...' : 'Tao tai khoan'}
            </button>
          </form>
          <p className="auth-footer">
            Da co tai khoan? <Link to="/dang-nhap">Dang nhap</Link>
          </p>
        </div>
      </div>
    </div>
  );
}
